1	import { run, BASE_PREMIUMS } from "./claim-office.js";
2	
3	type Item = { type: string };
4	type Damage = { itemType: string; amount: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: { damages: Damage[] } };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { steps: Step[] };
9	
10	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
11	
12	const failWith = (message: string): never => {
13	  console.error(message);
14	  process.exit(1);
15	};
16	
17	const validateQuote = (step: QuoteStep): void => {
18	  for (const item of step.items) {
19	    if (!isKnownItemType(item.type)) {
20	      failWith(`unknown item type: ${item.type}`);
21	    }
22	  }
23	};
24	
25	const validateClaim = (step: ClaimStep, scenario: Scenario): void => {
26	  const policyStep = scenario.steps[step.policy] as QuoteStep;
27	  const policyTypes = new Set(policyStep.items.map((i) => i.type));
28	  for (const damage of step.incident.damages) {
29	    if (damage.amount < 0) {
30	      failWith(`negative damage amount: ${damage.amount}`);
31	    }
32	    if (!policyTypes.has(damage.itemType)) {
33	      failWith(`damage references item not in policy: ${damage.itemType}`);
34	    }
35	  }
36	};
37	
38	const validateScenario = (scenario: Scenario): void => {
39	  for (const step of scenario.steps) {
40	    if (step.op === "quote") validateQuote(step);
41	    else if (step.op === "claim") validateClaim(step, scenario);
42	  }
43	};
44	
45	const readStdin = async (): Promise<string> => {
46	  const chunks: Buffer[] = [];
47	  for await (const chunk of process.stdin) {
48	    chunks.push(chunk as Buffer);
49	  }
50	  return Buffer.concat(chunks).toString("utf8");
51	};
52	
53	const main = async (): Promise<void> => {
54	  const scenario = JSON.parse(await readStdin()) as Scenario;
55	  validateScenario(scenario);
56	  console.log(JSON.stringify(run(scenario)));
57	};
58	
59	main();
